const category = url.searchParams.get("category");
const slug = url.searchParams.get("slug");

let authorStripeAccountId: string | undefined = undefined;
if (category && slug) {
  const entry = await readRegistryEntry(category, slug);
  if (entry?.stripeAccountId) {
    authorStripeAccountId = entry.stripeAccountId;
  }
}

const ip = req.headers.get("x-forwarded-for") || "unknown";
if (!checkRateLimit(`checkout:${ip}:${userId}`, 10, 60000)) {
  return new Response("Too many requests", { status: 429 });
}

const account = await stripe.accounts.retrieve(accountId);
if (account.metadata?.clerkUserId !== userId) {
  return new Response("Forbidden: Account does not belong to user", {
    status: 403,
  });
}

const loginLink = await stripe.accounts.createLoginLink(accountId);
